import{j as e,c as l,H as i,a as t,t as a,B as o,o as u}from"./DkqCqAzL.js";const n={class:"rounded-2xl border bg-white shadow-soft"},h={key:0,class:"px-5 pt-5"},d={class:"text-base font-semibold"},c={key:0,class:"text-sm text-slate-600 mt-1"},r={class:"p-5"},P=e({__name:"UiCard",props:{title:{},subtitle:{}},setup(b){return(p,V)=>(u(),l("div",n,[b.title?(u(),l("div",h,[t("div",d,a(b.title),1),b.subtitle?(u(),l("div",c,a(b.subtitle),1)):i("",!0)])):i("",!0),t("div",r,[o(p.$slots,"default")])]))}}),s={p1:"postulate-1",p2:"postulate-2",p3:"postulate-3",p4:"postulate-4"},m=[{id:"balanced",title:"План A — Сбалансированный",subtitle:"Умеренная вариативность V/P/R без перекосов",explanationHtml:`
<h3>1) Что мы считаем «моделью» плана</h3>
<p>
Вариант плана — это не просто таблица тренировок, а правило, как из базовой нагрузки (из периода наблюдения) получить последовательность
микроциклов до даты старта, сохраняя согласованность V/P/R через уравнение регрессии.
Смысл: <b>входы</b> (V, P, R) задают нагрузку, <b>выход</b> — прогнозируемый физиологический отклик (маркер Y).
</p>

<h3>2) Базовый уровень (точка отсчёта)</h3>
<p>
Из введённых недель наблюдения мы берём средние значения параметров нагрузки:
</p>
<div class="formula-block">
V<sub>0</sub>=mean(V),&nbsp; P<sub>0</sub>=mean(P),&nbsp; R<sub>0</sub>=mean(R)
</div>
<p>
И базовый уровень маркера (для выбранного контрольного маркера):
</p>
<div class="formula-block">
Y<sub>0</sub>=mean(Y),&nbsp; λ<sub>0</sub>=ln(Y<sub>0</sub>)
</div>

<h3>3) Нормировка изменений (Δ)</h3>
<p>
Чтобы работать с относительными изменениями (и корректно читать %‑эффекты), используем относительные приращения:
</p>
<div class="formula-block">
ΔV=(V-V<sub>0</sub>)/V<sub>0</sub>,&nbsp;
ΔP=(P-P<sub>0</sub>)/P<sub>0</sub>,&nbsp;
ΔR=(R-R<sub>0</sub>)/R<sub>0</sub>
</div>
<p>
Это напрямую связано с <a href="/#${s.p2}">Постулатом 2</a> (скорость изменения маркеров в %).
</p>

<h3>4) Регрессионная связь «нагрузка → маркер»</h3>
<p>
Мы используем логарифмическую множественную регрессию:
</p>
<div class="formula-block">
ln(Y)=b<sub>0</sub>+b<sub>1</sub>ΔV+b<sub>2</sub>ΔP+b<sub>3</sub>ΔR
</div>
<p>
Коэффициенты b отражают индивидуальную чувствительность спортсмена:
см. <a href="/#${s.p1}">Постулат 1</a>.
</p>

<h3>5) Как из этого получается план (ключевой вывод)</h3>
<p>
План строится так: мы <b>задаём желаемые</b> ΔV и ΔP (по типу недели: объём/интенсивность/восстановление/пик),
а ΔR вычисляем как компенсирующую поправку, чтобы удерживать контрольный маркер в запланированном коридоре.
Это прямое применение <a href="/#${s.p4}">Постулата 4</a>.
</p>
<div class="formula-block">
ΔR = ( ln(Y<sup>*</sup>) - b<sub>0</sub> - b<sub>1</sub>ΔV - b<sub>2</sub>ΔP ) / b<sub>3</sub>
</div>
<p>
Где Y<sup>*</sup> — целевое значение маркера на конкретную тренировку/неделю (в этом плане оно «мягко колеблется» вокруг Y<sub>0</sub>).
Далее восстанавливаем паузу:
</p>
<div class="formula-block">
R = R<sub>0</sub>⋅(1+ΔR)
</div>
<p>
При выходе за допустимые пределы проще всего корректировать именно R (см. <a href="/#${s.p3}">Постулат 3</a>).
</p>

<h3>6) Чем этот план отличается от других</h3>
<ul>
  <li><b>Сбалансированный</b>: умеренные изменения ΔV и ΔP, цель — ровная управляемая динамика без «перекосов».</li>
  <li>Вариативность присутствует, но приоритет — стабильность и предсказуемость.</li>
</ul>
`},{id:"volume",title:"План B — Объёмный",subtitle:"Акцент на V (тоннаж) при контролируемых паузах",explanationHtml:`
<h3>1) Идея плана</h3>
<p>
Цель — дать больший тренировочный стимул через рост объёма V (и умеренно через структуру P),
но не «вылететь» по биохимическому отклику. Управляем это через расчёт пауз R из уравнения.
</p>

<h3>2) Управляющие приоритеты</h3>
<ul>
  <li><b>Основной рычаг</b>: ΔV выше, чем в других планах.</li>
  <li><b>Компенсация</b>: ΔR подбирается так, чтобы контрольный маркер не уходил в опасную зону (<a href="/#${s.p4}">Постулат 4</a>).</li>
  <li><b>Почему это работает</b>: если спортсмен чувствителен к V (|b<sub>1</sub>| велик), то небольшое изменение V даёт заметный эффект по Y (<a href="/#${s.p1}">Постулат 1</a>).</li>
</ul>

<h3>3) Формулы (как именно считаем)</h3>
<p>
Мы задаём «более высокий» профиль ΔV(t) по микроциклам. Например, для объёмной недели:
</p>
<div class="formula-block">
ΔV(t) ↑,&nbsp; ΔP(t) ↑ (умеренно),&nbsp; затем ΔR(t) = ( ln(Y<sup>*</sup>) - b<sub>0</sub> - b<sub>1</sub>ΔV - b<sub>2</sub>ΔP ) / b<sub>3</sub>
</div>
<p>
Дальше восстанавливаем абсолютные значения:
</p>
<div class="formula-block">
V = V<sub>0</sub>⋅(1+ΔV),&nbsp; P=P<sub>0</sub>⋅(1+ΔP),&nbsp; R=R<sub>0</sub>⋅(1+ΔR)
</div>

<h3>4) Что вы увидите на графиках</h3>
<ul>
  <li>V — выше и контрастнее.</li>
  <li>P — чуть выше в объёмных неделях (больше подъёмов при меньшем среднем весе).</li>
  <li>R — будет «подтягиваться» вверх именно там, где комбинация V/P по уравнению повышает прогноз Y.</li>
</ul>
`},{id:"intensity",title:"План C — Интенсивностный",subtitle:"Акцент на «тяжелее средний вес» через P↓ и R↑",explanationHtml:`
<h3>1) Идея плана</h3>
<p>
Интенсивность в вашей постановке управляется через P (число подъёмов, инверсия классической интенсивности):
P↓ → средний вес↑. Этот план делает P более контрастным, а паузы R подбирает из регрессии так,
чтобы физиологический отклик оставался управляемым.
</p>

<h3>2) Управляющие приоритеты</h3>
<ul>
  <li><b>Основной рычаг</b>: ΔP ниже (P уменьшаем).</li>
  <li><b>Компенсация</b>: R увеличиваем настолько, насколько требуется уравнением (обычно ΔR>0).</li>
  <li><b>Интерпретация эффекта</b>: так как модель логарифмическая, изменения читаются в % (<a href="/#${s.p2}">Постулат 2</a>).</li>
</ul>

<h3>3) Вывод формулы коррекции R (пошагово)</h3>
<p>Берём базовый уровень (при ΔV=ΔP=ΔR=0):</p>
<div class="formula-block">
ln(Y<sub>0</sub>) = b<sub>0</sub>
</div>
<p>Для конкретной тренировки задаём ΔV и ΔP, а целевой уровень ставим близко к Y<sub>0</sub> (или ниже, если нужно разгрузить):</p>
<div class="formula-block">
ln(Y<sup>*</sup>) = b<sub>0</sub> + ε(t)
</div>
<p>Подставляем в регрессию и решаем относительно ΔR:</p>
<div class="formula-block">
ln(Y<sup>*</sup>) = b<sub>0</sub> + b<sub>1</sub>ΔV + b<sub>2</sub>ΔP + b<sub>3</sub>ΔR
\\
ΔR = ( ln(Y<sup>*</sup>) - b<sub>0</sub> - b<sub>1</sub>ΔV - b<sub>2</sub>ΔP ) / b<sub>3</sub>
</div>
<p>
Это и есть формализованная коррекция по <a href="/#${s.p4}">Постулату 4</a>, а выбор корректируемого параметра (обычно R) — по <a href="/#${s.p3}">Постулат 3</a>.
</p>

<h3>4) Что вы увидите на графиках</h3>
<ul>
  <li>P — заметно ниже в интенсивных неделях.</li>
  <li>R — «взлетает» именно там, где комбинация (V,P) иначе дала бы рост Y.</li>
  <li>V — может быть ниже, но не обязательно: в интенсивных неделях часто V немного снижается.</li>
</ul>
`},{id:"recovery",title:"План D — Восстановительный (бережный)",subtitle:"Меньше V, мягче волны; удерживаем маркеры ниже базового",explanationHtml:`
<h3>1) Идея плана</h3>
<p>
Это вариант, когда приоритет — <b>восстановление и устойчивость</b>: объём V снижается, волны мягче,
а паузы R подбираются так, чтобы контрольный маркер держался <b>ниже базового уровня</b>.
</p>

<h3>2) Для кого подходит</h3>
<ul>
  <li>После тяжёлого блока / накопленной усталости</li>
  <li>При «пограничных» маркерах и необходимости разгрузиться без полного отдыха</li>
  <li>Когда важнее стабильность, чем прогресс любой ценой</li>
</ul>

<h3>3) Что меняется по сравнению с планом A</h3>
<ul>
  <li>V — ниже</li>
  <li>P — ближе к базовому или чуть выше (больше «лёгкой» работы)</li>
  <li>R — чаще растёт, потому что это самый “дешёвый” рычаг для снижения отклика (<a href="/#${s.p3}">Постулат 3</a>)</li>
</ul>
`},{id:"performance",title:"План E — Соревновательный (под результат)",subtitle:"Меньше P (тяжелее), умеренный V, R под контролем по уравнению",explanationHtml:`
<h3>1) Идея плана</h3>
<p>
Этот вариант делает нагрузку «ближе к соревновательной»: <b>P ниже</b> (средний вес выше),
V умеренный, а R рассчитывается из регрессии так, чтобы держать физиологический отклик управляемым.
</p>

<h3>2) Чем отличается от плана C</h3>
<ul>
  <li>Волны более ровные (меньше «качелей» внутри недели)</li>
  <li>Целевой уровень маркера чуть ниже базового: меньше риска “перегреть” план</li>
  <li>Ориентация — на аккуратный перенос в пик без резких провалов/вылетов</li>
</ul>
`}];export{P as _,m as a,s as p};
